import React, { useState, useEffect } from 'react';
import './OTPVerification.css';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const OTPVerification = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { sendEmailOTP, sendPhoneOTP, verifyOTP } = useAuth();

  const email = location.state?.email;
  const phone = location.state?.phone;

  const [emailOTP, setEmailOTP] = useState('');
  const [phoneOTP, setPhoneOTP] = useState('');
  const [emailVerified, setEmailVerified] = useState(false);
  const [phoneVerified, setPhoneVerified] = useState(false);
  const [error, setError] = useState('');
  const [info, setInfo] = useState('');
  const [loading, setLoading] = useState(false);
  const [sendingEmail, setSendingEmail] = useState(false);
  const [sendingPhone, setSendingPhone] = useState(false);

  useEffect(() => {
    if (!email || !phone) {
      navigate('/login');
    }
  }, [email, phone, navigate]);

  useEffect(() => {
    if (!email || !phone) {
      return;
    }

    const sendInitialOtps = async () => {
      setSendingEmail(true);
      setSendingPhone(true);
      setError('');
      setInfo('Sending verification codes...');

      try {
        await Promise.all([sendEmailOTP(email), sendPhoneOTP(phone)]);
        setInfo('Codes sent. Enter each 6-digit code below.');
      } catch (err) {
        setInfo('');
        setError(err.response?.data?.message || 'Could not send one or more codes. Please resend.');
      } finally {
        setSendingEmail(false);
        setSendingPhone(false);
      }
    };

    sendInitialOtps();
  }, [email, phone, sendEmailOTP, sendPhoneOTP]);

  const handleSendEmailOTP = async () => {
    setSendingEmail(true);
    try {
      await sendEmailOTP(email);
      setError('');
      setInfo('Email code sent again.');
    } catch (err) {
      setInfo('');
      setError(err.response?.data?.message || 'Failed to send email code.');
    } finally {
      setSendingEmail(false);
    }
  };

  const handleSendPhoneOTP = async () => {
    setSendingPhone(true);
    try {
      await sendPhoneOTP(phone);
      setError('');
      setInfo('Phone code sent again.');
    } catch (err) {
      setInfo('');
      setError(err.response?.data?.message || 'Failed to send phone code.');
    } finally {
      setSendingPhone(false);
    }
  };

  const handleVerifyEmailOTP = async () => {
    if (emailOTP.length !== 6) {
      setError('Enter a valid 6-digit email code.');
      return;
    }

    setLoading(true);
    try {
      await verifyOTP(email, emailOTP, 'email');
      setEmailVerified(true);
      setError('');
      setInfo('Email verified.');
    } catch (err) {
      setInfo('');
      setError(err.response?.data?.message || 'Invalid email code.');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyPhoneOTP = async () => {
    if (phoneOTP.length !== 6) {
      setError('Enter a valid 6-digit phone code.');
      return;
    }

    setLoading(true);
    try {
      await verifyOTP(phone, phoneOTP, 'phone');
      setPhoneVerified(true);
      setError('');
      setInfo('Phone verified.');
    } catch (err) {
      setInfo('');
      setError(err.response?.data?.message || 'Invalid phone code.');
    } finally {
      setLoading(false);
    }
  };

  const handleComplete = () => {
    if (emailVerified && phoneVerified) {
      navigate('/login');
    }
  };

  return (
    <div className="otp-verification-container">
      <div className="otp-verification-card">
        <h1>Verify Your Account</h1>
        <p className="subtitle">Enter the 6-digit codes sent to your email and phone</p>

        {error && <div className="error-message">{error}</div>}
        {info && <div className="info-message">{info}</div>}

        <div className="verification-section">
          <div className="verification-header">
            <h2>Email Verification</h2>
            {emailVerified && <span className="verified-badge">✓ Verified</span>}
          </div>

          {!emailVerified ? (
            <div className="verification-form">
              <p className="info-text">Email: {email}</p>
              <button
                type="button"
                onClick={handleSendEmailOTP}
                className="btn btn-secondary"
                disabled={sendingEmail}
              >
                {sendingEmail ? 'Sending...' : 'Resend code'}
              </button>

              <div className="form-group">
                <label htmlFor="emailOTP">Enter OTP</label>
                <input
                  type="text"
                  id="emailOTP"
                  value={emailOTP}
                  onChange={(e) => setEmailOTP(e.target.value.replace(/\D/g, ''))}
                  placeholder="000000"
                  maxLength="6"
                  inputMode="numeric"
                />
              </div>

              <button
                type="button"
                onClick={handleVerifyEmailOTP}
                className="btn btn-primary"
                disabled={loading || !emailOTP}
              >
                Verify Email
              </button>
            </div>
          ) : (
            <p className="verified-text">Email verified successfully!</p>
          )}
        </div>

        <div className="verification-section">
          <div className="verification-header">
            <h2>Phone Verification</h2>
            {phoneVerified && <span className="verified-badge">✓ Verified</span>}
          </div>

          {!phoneVerified ? (
            <div className="verification-form">
              <p className="info-text">Phone: {phone}</p>
              <button
                type="button"
                onClick={handleSendPhoneOTP}
                className="btn btn-secondary"
                disabled={sendingPhone}
              >
                {sendingPhone ? 'Sending...' : 'Resend code'}
              </button>

              <div className="form-group">
                <label htmlFor="phoneOTP">Enter OTP</label>
                <input
                  type="text"
                  id="phoneOTP"
                  value={phoneOTP}
                  onChange={(e) => setPhoneOTP(e.target.value.replace(/\D/g, ''))}
                  placeholder="000000"
                  maxLength="6"
                  inputMode="numeric"
                />
              </div>

              <button
                type="button"
                onClick={handleVerifyPhoneOTP}
                className="btn btn-primary"
                disabled={loading || !phoneOTP}
              >
                Verify Phone
              </button>
            </div>
          ) : (
            <p className="verified-text">Phone verified successfully!</p>
          )}
        </div>

        {emailVerified && phoneVerified && (
          <button
            type="button"
            onClick={handleComplete}
            className="btn btn-success"
          >
            Continue to Login
          </button>
        )}
      </div>
    </div>
  );
};

export default OTPVerification;
